function Test-PathMatchesGlob {
    <#
    .SYNOPSIS
        Test whether a single path matches a glob pattern.

    .DESCRIPTION
        Special-cases the leading '**/' pattern so that '**/foo' also matches
        a top-level 'foo' (the conventional "anywhere in tree" globstar).
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string]$Path,
        [Parameter(Mandatory)][string]$Pattern
    )

    $regex = Convert-GlobToRegex $Pattern
    if ($Path -match $regex) { return $true }

    # '**/x' should also match top-level 'x' (no preceding directory).
    if ($Pattern.StartsWith('**/')) {
        $rest = $Pattern.Substring(3)
        $restRegex = Convert-GlobToRegex $rest
        if ($Path -match $restRegex) { return $true }
    }
    return $false
}

